module calendar
(
    input CLK,
    input RST,
    output reg [5:0] Hours,
    output reg [5:0] Mins,
    output reg [5:0] Secs
);
    parameter MAX_SECONDS = 59;
    parameter MAX_MINUTES = 59;
    parameter MAX_HOURS = 23;
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Secs_next <= 0;
        end else if (Secs == MAX_SECONDS) begin
            Secs_next <= 0;
        end else begin
            Secs_next <= Secs + 1;
        end
    end
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Mins_next <= 0;
        end else if (Mins == MAX_MINUTES && Secs == MAX_SECONDS) begin
            Mins_next <= 0;
        end else if (Secs == MAX_SECONDS) begin
            Mins_next <= Mins + 1;
        end else begin
            Mins_next <= Mins;
        end
    end
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Hours_next <= 0;
        end else if (Hours == MAX_HOURS && Mins == MAX_MINUTES && Secs == MAX_SECONDS) begin
            Hours_next <= 0;
        end else if (Mins == MAX_MINUTES && Secs == MAX_SECONDS) begin
            Hours_next <= Hours + 1;
        end else begin
            Hours_next <= Hours;
        end
    end
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Secs <= 0;
        end else begin
            Secs <= Secs_next;
        end
    end
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Mins <= 0;
        end else begin
            Mins <= Mins_next;
        end
    end
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Hours <= 0;
        end else begin
            Hours <= Hours_next;
        end
    end
endmodule
